#include <iostream>
#include <string>
#include <sstream>
#include <streambuf>

// The student's main function is typically renamed for testing.
// For this driver, we assume 'main' is the entry point and we redirect streams.
// If the student's code were in a function like 'student_solution()', 
// this driver would call that function.

std::string run_student_code(const std::string& input_str) {
    std::stringstream ss_input(input_str);
    std::stringstream ss_output;

    // Save original cin/cout buffers
    std::streambuf* old_cin_buf = std::cin.rdbuf();
    std::streambuf* old_cout_buf = std::cout.rdbuf();

    // Redirect cin and cout
    std::cin.rdbuf(ss_input.rdbuf());
    std::cout.rdbuf(ss_output.rdbuf());

    // Call the student's main function (assuming it's named 'main')
    // For a real test harness, you might rename student's main to avoid conflicts
    // or compile it into a separate executable.
    int result = main(); 

    // Restore original cin/cout buffers
    std::cin.rdbuf(old_cin_buf);
    std::cout.rdbuf(old_cout_buf);

    return ss_output.str();
}
